public function webnuConnect(Request $request): JsonResponse
{
    $data = $request->validate([
        'api_token' => ['required', 'string', 'min:20'],
        'base_url' => ['nullable', 'url'],
        'app_key' => ['nullable', 'string'],
    ]);

    if (! $this->webnu->isConfigured() && ! config('integrations.mock')) {
        return response()->json([
            'message' => 'Webnu no está configurado. Define WEBNU_API_URL en el .env de TVPik.',
        ], 503);
    }

    try {
        $connection = $this->webnu->connect(
            $request->user(),
            $data['api_token'],
            $data['base_url'] ?? null,
            $data['app_key'] ?? null,
        );
    } catch (\Throwable $e) {
        Log::error('Webnu connect failed', ['error' => $e->getMessage()]);

        return response()->json([
            'message' => 'No se pudo conectar con Webnu: ' . $e->getMessage(),
        ], 422);
    }

    return response()->json([
        'message' => 'Webnu conectado correctamente.',
        'account' => $connection->provider_user_id,
        'base_url' => $connection->scopes['base_url'] ?? null,
    ]);
}

public function webnuDisconnect(Request $request): JsonResponse
{
    $request->user()->oauthConnections()->where('provider', 'webnu')->delete();

    return response()->json(['message' => 'Webnu desconectado.']);
}

public function webnuMenus(Request $request): JsonResponse
{
    $connection = $this->requireConnection($request, 'webnu');

    return response()->json([
        'data' => $this->webnu->listMenus($connection),
    ]);
}

public function webnuSync(Request $request): JsonResponse
{
    $data = $request->validate([
        'gallery_id' => ['required', 'integer', 'exists:galleries,id'],
        'slug' => ['required', 'string', 'max:255'],
        'async' => ['nullable', 'boolean'],
        'force' => ['nullable', 'boolean'],
    ]);

    $gallery = Gallery::where('id', $data['gallery_id'])
        ->where('user_id', $request->user()->id)
        ->firstOrFail();

    $connection = $this->requireConnection($request, 'webnu');

    if ($data['async'] ?? false) {
        SyncWebnuGallery::dispatch(
            $request->user()->id,
            $gallery->id,
            $data['slug'],
            (bool) ($data['force'] ?? false),
        );

        return response()->json([
            'message' => 'Sincronización con Webnu iniciada.',
            'queued' => true,
        ], 202);
    }

    try {
        $result = $this->webnuSync->sync(
            $gallery,
            $connection,
            $data['slug'],
            (bool) ($data['force'] ?? false),
        );
    } catch (\Throwable $e) {
        Log::error('Webnu sync failed', ['error' => $e->getMessage()]);

        return response()->json(['message' => $e->getMessage()], 422);
    }

    return response()->json([
        'message' => $result['changed']
            ? 'Carta sincronizada con la galería.'
            : 'La carta ya estaba actualizada.',
        'changed' => $result['changed'],
        'sync_version' => $result['sync_version'],
        'display_url' => $result['display_url'] ?? null,
        'menu_type' => $result['menu_type'] ?? null,
    ]);
}

private function requireConnection(Request $request, string $provider): OauthConnection

