public function syncWebnu(Request $request, Gallery $gallery, WebnuGallerySyncService $webnuSync): JsonResponse
{
    $this->authorizeGallery($request, $gallery);

    $data = $request->validate([
        'slug' => ['required', 'string', 'max:255'],
        'force' => ['nullable', 'boolean'],
    ]);

    $connection = $request->user()->oauthConnection('webnu');
    if (! $connection) {
        return response()->json(['message' => 'Conecta Webnu primero en Integraciones.'], 422);
    }

    try {
        $result = $webnuSync->sync(
            $gallery,
            $connection,
            $data['slug'],
            (bool) ($data['force'] ?? false),
        );
    } catch (\Throwable $e) {
        return response()->json(['message' => $e->getMessage()], 422);
    }

    return response()->json([
        'message' => $result['changed']
            ? 'Carta Webnu sincronizada.'
            : 'La carta ya estaba actualizada.',
        'changed' => $result['changed'],
        'sync_version' => $result['sync_version'],
    ]);
}

