export function useConnectWebnu() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: (body: { api_token: string; base_url?: string; app_key?: string }) =>
      api.post('/integrations/webnu/connect', body),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['integrations'] }),
  })
}

export function useDisconnectWebnu() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: () => api.delete('/integrations/webnu/disconnect'),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['integrations'] }),
  })
}

export function useSyncWebnuGallery() {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: (body: { gallery_id: number; slug: string; force?: boolean }) =>
      api.post('/integrations/webnu/sync', body),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['integrations'] })
      qc.invalidateQueries({ queryKey: ['galleries'] })
    },
  })
}

export function useSyncWebnuGalleryById(galleryId: number) {
  const qc = useQueryClient()
  return useMutation({
    mutationFn: (body: { slug: string; force?: boolean }) =>
      api.post(`/galleries/${galleryId}/sync-webnu`, body),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['integrations'] })
      qc.invalidateQueries({ queryKey: ['galleries'] })
      qc.invalidateQueries({ queryKey: ['galleries', galleryId] })
    },
  })
}

