/**
 * Webnu Admin App Shell — design system (TVPik-inspired + corporate navy/blue)
 */
:root {
    --webnu-navy: #000529;
    --webnu-blue-dark: #002055;
    --webnu-blue-mid: #005db5;
    --webnu-blue: #0074d9;
    --webnu-gradient: linear-gradient(90deg, #000529 0%, #002055 35%, #005db5 70%, #0074d9 100%);
    --webnu-surface: #ffffff;
    --webnu-bg: #f4f6f9;
    --webnu-border: #e8ecf1;
    --webnu-text: #0f172a;
    --webnu-text-muted: #64748b;
    --webnu-sidebar-width: 16rem;
    --webnu-radius: 0.75rem;
    --webnu-shadow: 0 1px 3px rgba(15, 23, 42, 0.06), 0 1px 2px rgba(15, 23, 42, 0.04);
    --webnu-shadow-md: 0 4px 12px rgba(15, 23, 42, 0.08);
}

/* Reset AdminLTE layout when using webnu-app */
.webnu-app {
    font-family: "DM Sans", system-ui, -apple-system, sans-serif;
    background: var(--webnu-bg);
    color: var(--webnu-text);
    margin: 0;
    min-height: 100vh;
    -webkit-font-smoothing: antialiased;
}

.webnu-app .wrapper {
    display: flex;
    min-height: 100vh;
    overflow: hidden;
}

.webnu-app .main-header,
.webnu-app .main-sidebar,
.webnu-app .main-footer,
.webnu-app .content-wrapper {
    display: none !important;
}

/* Shell layout */
.webnu-shell {
    display: flex;
    min-height: 100vh;
    width: 100%;
}

.webnu-sidebar {
    position: fixed;
    top: 0;
    left: 0;
    z-index: 1040;
    display: flex;
    flex-direction: column;
    width: var(--webnu-sidebar-width);
    height: 100vh;
    background: var(--webnu-navy);
    color: #e2e8f0;
    border-right: 1px solid rgba(255, 255, 255, 0.06);
    transform: translateX(0);
    transition: transform 0.25s ease;
}

.webnu-sidebar.is-closed {
    transform: translateX(-100%);
}

.webnu-sidebar__brand {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 1.25rem 1rem;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    text-decoration: none;
    color: #fff;
}

.webnu-sidebar__brand img {
    height: 36px;
    width: auto;
}

.webnu-sidebar__brand-text {
    display: flex;
    flex-direction: column;
}

.webnu-sidebar__brand-name {
    font-size: 1.125rem;
    font-weight: 700;
    line-height: 1.2;
}

.webnu-sidebar__brand-sub {
    font-size: 0.7rem;
    color: #94a3b8;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.webnu-sidebar__nav {
