input.contents:
/**
 * Webnu Panel — UI mobile-first (mockup Webnu.es)
 */
:root {
  --wn-navy: #002055;
  --wn-navy-deep: #000529;
  --wn-blue: #0074d9;
  --wn-bg: #f0f2f5;
  --wn-surface: #ffffff;
  --wn-text: #1a2332;
  --wn-muted: #6b7a90;
  --wn-border: #e4e9f0;
  --wn-radius: 14px;
  --wn-radius-sm: 10px;
  --wn-shadow: 0 2px 12px rgba(0, 32, 85, 0.06);
  --wn-header-h: 56px;
  --wn-bottom-nav-h: 64px;
  --wn-font: "Inter", system-ui, -apple-system, sans-serif;
}

.webnu-panel {
  font-family: var(--wn-font);
  background: var(--wn-bg);
  color: var(--wn-text);
  min-height: 100vh;
  margin: 0;
}

.webnu-panel *,
.webnu-panel *::before,
.webnu-panel *::after {
  box-sizing: border-box;
}

.webnu-panel__frame {
  min-height: 100vh;
  max-width: 480px;
  margin: 0 auto;
  background: var(--wn-bg);
  display: flex;
  flex-direction: column;
  position: relative;
  box-shadow: 0 0 0 1px var(--wn-border);
}

@media (min-width: 992px) {
  .webnu-panel__frame {
    margin-top: 1.5rem;
    margin-bottom: 1.5rem;
    min-height: calc(100vh - 3rem);
    border-radius: 20px;
    overflow: hidden;
    box-shadow: 0 8px 40px rgba(0, 32, 85, 0.12);
  }
}

/* Top bar */
.webnu-topbar {
  height: var(--wn-header-h);
  padding: 0 1rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--wn-surface);
  border-bottom: 1px solid var(--wn-border);
  flex-shrink: 0;
  position: sticky;
  top: 0;
  z-index: 100;
}

.webnu-topbar__brand {
  font-size: 1.125rem;
  font-weight: 700;
  color: var(--wn-navy);
  text-decoration: none;
  letter-spacing: -0.02em;
}

.webnu-topbar__brand span {
  color: var(--wn-blue);
}

.webnu-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--wn-navy) 0%, var(--wn-blue) 100%);
  color: #fff;
  font-size: 0.875rem;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  cursor: pointer;
  text-decoration: none;
}

/* Main */
.webnu-panel__main {
  flex: 1;
  padding: 1rem 1rem calc(var(--wn-bottom-nav-h) + 1rem);
  overflow-x: hidden;
}

/* Page hero */
.webnu-page-hero {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}

.webnu-page-hero--stack {
  flex-direction: column;
  align-items: stretch;
}

.webnu-page-hero__title {
  font-size: 1.625rem;
  font-weight: 700;
  line-height: 1.2;
  margin: 0;
  color: var(--wn-navy-deep);
  letter-spacing: -0.03em;
}

.webnu-page-hero__subtitle {
  margin: 0.35rem 0 0;
  font-size: 0.9375rem;
  color: var(--wn-muted);
  line-height: 1.45;
}

.webnu-page-hero__toolbar {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  flex-shrink: 0;
}

.webnu-icon-btn {
  width: 40px;
  height: 40px;
  border: none;
  background: transparent;
  border-radius: 50%;
  color: var(--wn-navy);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 1.125rem;
  cursor: pointer;
  text-decoration: none;
}

.webnu-icon-btn:hover {
  background: rgba(0, 32, 85, 0.06);
  color: var(--wn-navy);
}

/* Cards */
.webnu-card {
  background: var(--wn-surface);
  border: 1px solid var(--wn-border);
  border-radius: var(--wn-radius);
  box-shadow: var(--wn-shadow);
  margin-bottom: 1rem;
  overflow: hidden;
}

.webnu-card__body {
  padding: 1.125rem 1.25rem;
}

/* Buttons */
.btn-wn,
.webnu-btn--primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.75rem 1.25rem;
  font-size: 0.9375rem;
  font-weight: 600;
  border-radius: var(--wn-radius-sm);
  border: none;
  background: var(--wn-navy);
  color: #fff !important;
  text-decoration: none;
  cursor: pointer;
  width: 100%;
  transition: opacity 0.15s;
}

.btn-wn:hover,
.webnu-btn--primary:hover {
  opacity: 0.92;
  color: #fff;
}

.btn-wn--outline,
.webnu-btn--secondary {
  background: var(--wn-surface);
  color: var(--wn-navy) !important;
  border: 1.5px solid var(--wn-navy);
}

.btn-wn--ghost,
.webnu-btn--ghost {
  background: #f4f6f9;
  color: var(--wn-text) !important;
  border: 1px solid var(--wn-border);
}

.btn-wn--sm,
.webnu-btn--sm {
  padding: 0.45rem 0.85rem;
  font-size: 0.8125rem;
  width: auto;
}

.btn-wn--dashed,
.webnu-btn--dashed {
  background: transparent;
  border: 1.5px dashed var(--wn-border);
  color: var(--wn-blue) !important;
  width: 100%;
}

.webnu-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.35rem;
  font-weight: 600;
  text-decoration: none;
  border-radius: var(--wn-radius-sm);
  cursor: pointer;
  border: none;
}

.webnu-btn--block {
  width: 100%;
}

/* Dashboard tiles */
.webnu-dash-tile {
  text-align: center;
  padding: 1.5rem 1.25rem 1.25rem;
}

.webnu-dash-tile__icon {
  width: 52px;
  height: 52px;
  margin: 0 auto 0.75rem;
  border-radius: 14px;
  background: rgba(0, 116, 217, 0.1);
  color: var(--wn-navy);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.35rem;
}

.webnu-dash-tile h3 {
  font-size: 1.0625rem;
  font-weight: 700;
  margin: 0 0 0.35rem;
}

.webnu-dash-tile p {
  font-size: 0.8125rem;
  color: var(--wn-muted);
  margin: 0 0 1rem;
  line-height: 1.4;
