  font-weight: 700;
  line-height: 1.25;
  margin: 0 0 1rem;
  max-width: 16rem;
}

.webnu-promo .btn-wn {
  background: #fff;
  color: var(--wn-navy) !important;
  width: auto;
  padding: 0.55rem 1.1rem;
  font-size: 0.875rem;
}

/* Integrations */
.webnu-integ-card {
  background: var(--wn-surface);
  border: 1px solid var(--wn-border);
  border-radius: var(--wn-radius);
  padding: 1.125rem 1.25rem;
