    function initFlashAlerts() {
        document.querySelectorAll('.alert.alert-dismissible').forEach(function (alert) {
            window.setTimeout(function () {
                if (alert.parentNode) {
                    alert.classList.remove('show');
                    window.setTimeout(function () {
                        alert.remove();
                    }, 300);
                }
            }, 6000);
        });
    }

    function initOrdersPlaceholder() {
        var btn = document.getElementById('webnu-orders-soon');
        if (!btn) {
            return;
        }
        btn.addEventListener('click', function () {
            window.alert('Pedidos online estará disponible próximamente.');
        });
    }

    function initSectionAccordion() {
        document.querySelectorAll('.webnu-menu-section__head').forEach(function (head) {
            head.addEventListener('click', function (e) {
                if (e.target.closest('.webnu-menu-section__drag')) {
                    return;
                }
                var section = head.closest('.webnu-menu-section');
                if (section) {
                    section.classList.toggle('is-open');
                }
            });
        });
    }

    function init() {
        initCompanySelect();
        initFlashAlerts();
        initOrdersPlaceholder();
        initSectionAccordion();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();

