function setMenuTypePanels(isCustom) {
    if (isCustom) {
        $('#custom-menu').show();
        $('#pdf-menu').hide();
    } else {
        $('#custom-menu').hide();
        $('#pdf-menu').show();
    }
}

$(document).ready(function () {
